import './App.css';



import { BrowserRouter as Router, Route, Routes} from 'react-router-dom';
import Home from './containers/Home/Home'
import {Container, Nav, Navbar, NavDropdown} from "react-bootstrap";
function App() {
  return (
      <Router>
          <Routes>
              <Route path="/" element={<Home />} />
          </Routes>
      </Router>
  );
}

export default App;
